// 指令解析（支援整月 + 區間 + 單日查詢）
const CONFIG = {
  warehouses: ['TAO1','TAO3','TAO4','TAO5','TAO6','TAO7','TAO10'],
  intentKeywords: [
    { keywords: ['病假統計'], intent: 'sick_leave_stats' },
    { keywords: ['特休統計'], intent: 'leave_stats' },
    { keywords: ['請假統計'], intent: 'leave_stats' },
    { keywords: ['請假狀況','請假'], intent: 'leave_status' },
    { keywords: ['出勤時數','出勤時間','工時查詢','打卡'], intent: 'attendance_stats' },
    { keywords: ['出勤人員','出勤明細','出勤報表'], intent: 'attendance_detail' },
    { keywords: ['出勤統計'], intent: 'attendance_stats' },
  ],
  leaveTypeKeywords: [
    { keywords: ['病假','病'], leaveType: '病假' },
    { keywords: ['事假','事'], leaveType: '事假' },
    { keywords: ['特休','特'], leaveType: '特休' },
    { keywords: ['曠職','曠'], leaveType: '曠職' },
    { keywords: ['公假'], leaveType: '公假' },
    { keywords: ['國定假日','國假'], leaveType: '國定假日' },
  ],
};
const query = ($input.first().json.body?.query || '').trim();
if (!query) return [{ json: { success:false, error:'請提供查詢指令', hint:'範例：4/2請假狀況、3月特休統計、3/15~4/1特休' } }];

function parseDate(q) {
  const now = new Date();
  const yr = now.getFullYear();

  // 區間：3/15~4/1 or 3/15-4/1 or 3/15到4/1 or 2026/3/15~2026/4/1
  let m = q.match(/(\d{4})[\/-](\d{1,2})[\/-](\d{1,2})\s*[~\-到至]\s*(\d{4})[\/-](\d{1,2})[\/-](\d{1,2})/);
  if (m) return { dateFrom: m[1]+'-'+String(m[2]).padStart(2,'0')+'-'+String(m[3]).padStart(2,'0'),
                  dateTo: m[4]+'-'+String(m[5]).padStart(2,'0')+'-'+String(m[6]).padStart(2,'0'), dateMode: 'range' };
  m = q.match(/(\d{1,2})[\/-](\d{1,2})\s*[~\-到至]\s*(\d{1,2})[\/-](\d{1,2})/);
  if (m) return { dateFrom: yr+'-'+String(m[1]).padStart(2,'0')+'-'+String(m[2]).padStart(2,'0'),
                  dateTo: yr+'-'+String(m[3]).padStart(2,'0')+'-'+String(m[4]).padStart(2,'0'), dateMode: 'range' };

  // 單日完整：2026/4/2
  m = q.match(/(\d{4})[\/-](\d{1,2})[\/-](\d{1,2})/);
  if (m) return { date: m[1]+'-'+String(m[2]).padStart(2,'0')+'-'+String(m[3]).padStart(2,'0'), dateMode: 'day' };
  // 單日：4/2
  m = q.match(/(\d{1,2})[\/-](\d{1,2})/);
  if (m) return { date: yr+'-'+String(m[1]).padStart(2,'0')+'-'+String(m[2]).padStart(2,'0'), dateMode: 'day' };
  // 整月：3月
  m = q.match(/(\d{1,2})\s*月/);
  if (m) return { date: yr+'-'+String(m[1]).padStart(2,'0'), dateMode: 'month' };
  // 無日期 → 當月
  return { date: yr+'-'+String(now.getMonth()+1).padStart(2,'0'), dateMode: 'month' };
}

function parseIntent(q) {
  for (const r of CONFIG.intentKeywords) for (const k of r.keywords) if (q.includes(k)) return r.intent;
  return 'leave_status';
}
function parseWH(q) {
  if (/全部倉|所有倉|全倉/.test(q)) return CONFIG.warehouses.slice();
  const f=[]; for (const w of CONFIG.warehouses) if (q.toUpperCase().includes(w)) f.push(w);
  return f.length ? f : CONFIG.warehouses.slice();
}
function parseLT(q) {
  for (const r of CONFIG.leaveTypeKeywords) for (const k of r.keywords) if (q.includes(k)) return r.leaveType;
  return '';
}

const emails = $input.first().json.body?.emails || [];
const emails = ($input.first().json.body?.emails) || [];
const dateInfo = parseDate(query);
const intent = parseIntent(query);
const leaveType = parseLT(query);
const finalIntent = (leaveType && ['leave_status','attendance_detail'].includes(intent)) ? 'leave_stats' : intent;

// Person name extraction
let personName = '';
let tmp = query;
tmp = tmp.replace(/\d{4}[\/\-]\d{1,2}[\/\-]\d{1,2}/g, '');
tmp = tmp.replace(/\d{1,2}[\/\-]\d{1,2}/g, '');
tmp = tmp.replace(/\d{1,2}\s*月/g, '');
tmp = tmp.replace(/[~\-到至]/g, '');
for (const w of CONFIG.warehouses) tmp = tmp.replace(new RegExp(w, 'gi'), '');
const removeKw = ['全部倉','所有倉','全倉','病假統計','特休統計','請假統計','請假狀況','請假',
  '出勤時數','出勤時間','工時查詢','打卡','出勤人員','出勤明細','出勤報表','出勤統計',
  '病假','事假','特休','曠職','公假','國定假日','國假',
  '假別統計','統計','查詢','的','全部'];
for (const kw of removeKw) tmp = tmp.replace(new RegExp(kw, 'g'), '');
tmp = tmp.replace(/[a-zA-Z0-9\s]/g, '').trim();
if (tmp.length >= 2 && tmp.length <= 4) personName = tmp;

return [{ json: { success:true, parsed: {
  intent: finalIntent,
  ...dateInfo,
  warehouse: parseWH(query),
  leaveType,
  needReport: true
, personName}, originalQuery: query, emails } }];

// 組裝讀取參數
const CONFIG = {
  spreadsheetMap: {
    'TAO1':'1_bhGQdx0YH7lsqPFEq5___6_Nwq_gbelJmIHv0bmaIE',
    'TAO3':'1cffI2jIVZA1uSiAyaLLXXgPzDByhy87xznaN85O7wEE',
    'TAO4':'1tVxQbV0298fn2OXWAF0UqZa7FLbypsatciatxs4YVTU',
    'TAO5':'1jzVXC6gt36hJtlUHoxtTzZLMNj4EtTsd4k8eNB1bdiA',
    'TAO6':'1wwPLSLjl2abfM_OMdTNI9PoiPKo3waCV_y0wmx2DxAE',
    'TAO7':'16nGCqRO8DYDm0PbXFbdt-fiEFZCXxXjlOWjKU67p4LY',
    'TAO10':'1y0w49xdFlHvcVtgtG8fq6zdrF26y8j7HMFh5ujzUyR4',
  },
  intentSheetType: { 'leave_status':'leave','sick_leave_stats':'leave','leave_stats':'leave','attendance_detail':'work','attendance_stats':'work' },
  sheetKeywords: { leave:['班表','出勤記錄','假況'], work:['出勤時數','出勤時間','工時'] },
};
const prev = $('指令解析').first().json;
const p = prev.parsed;
const st = CONFIG.intentSheetType[p.intent]||'leave';

// 區間查詢可能跨月，需要讀取多個分頁
// 先傳遞所有日期資訊，讓後續節點處理
const results = [];
for (const wh of p.warehouse) {
  const sid = CONFIG.spreadsheetMap[wh]; if (!sid) continue;
  results.push({ json: {
    warehouse:wh, spreadsheetId:sid, sheetType:st,
    sheetKeywords:CONFIG.sheetKeywords[st],
    intent:p.intent,
    date:p.date||'', dateFrom:p.dateFrom||'', dateTo:p.dateTo||'',
    dateMode:p.dateMode||'day',
    leaveType:p.leaveType, needReport:p.needReport,
    originalQuery:prev.originalQuery, personName:p.personName||'', emails:p.emails||prev.emails||[]
  } });
}
return results;

// 解析分頁，組裝資料 URL（支援區間跨月）
const CONFIG = { sheetKeywords: { leave:['班表','出勤記錄','假況'], work:['出勤時數','出勤時間','工時'] } };
let prev; try { prev = $('組裝讀取參數').first().json; } catch(e) { prev = $input.first().json; }
const meta = $input.first().json;
const wh = prev.warehouse, sid = prev.spreadsheetId, st = prev.sheetType;
const dm = prev.dateMode || 'day';
const kw = CONFIG.sheetKeywords[st]||CONFIG.sheetKeywords.leave;

if (meta.error || !meta.sheets) {
  return [{ json: { ...prev, dateMode:dm, allSheetNames:[], warning:wh+' 無法取得分頁', dataUrl:'', success:false } }];
}
const names = meta.sheets.map(s=>s.properties.title);

// 決定要查哪些月份
let months = [];
if (dm === 'range') {
  const mFrom = parseInt((prev.dateFrom||'').split('-')[1]) || 0;
  const mTo = parseInt((prev.dateTo||'').split('-')[1]) || 0;
  if (mFrom && mTo) {
    for (let m = mFrom; m <= mTo; m++) months.push(m);
    if (mTo < mFrom) { // 跨年不太可能，但保險
      for (let m = mFrom; m <= 12; m++) months.push(m);
      for (let m = 1; m <= mTo; m++) months.push(m);
    }
  }
} else if (dm === 'month') {
  const m = parseInt((prev.date||'').split('-')[1]) || 0;
  if (m) months.push(m);
} else {
  const m = parseInt((prev.date||'').split('-')[1]) || 0;
  if (m) months.push(m);
}
months = [...new Set(months)];

// 為每個月份找對應分頁
const targets = [];
for (const mo of months) {
  const monthStr = mo + '月';
  let target = null;
  for (const k of kw) { const f=names.find(n=>n.includes(k)&&n.includes(monthStr)); if(f){target=f;break;} }
  if (!target) { for (const k of kw) { const f=names.find(n=>n.includes(k)); if(f){target=f;break;} } }
  if (!target) target = names[0]||'Sheet1';
  if (!targets.includes(target)) targets.push(target);
}

// 如果沒找到任何月份，fallback
if (targets.length === 0) {
  for (const k of kw) { const f=names.find(n=>n.includes(k)); if(f){targets.push(f);break;} }
  if (targets.length === 0) targets.push(names[0]||'Sheet1');
}

// 輸出多個分頁請求
const results = [];
for (const t of targets) {
  results.push({ json: {
    ...prev, dateMode:dm, sheetName:t, allSheetNames:names, warning:null,
    dataUrl:'http://localhost:3456/sheets/data?spreadsheetId='+sid+'&sheetName='+encodeURIComponent(t),
    success:true
  } });
}
return results;

// 資料標準化（修正欄位索引 + header 正規化）
const CONFIG = {
  leaveStatusMapping: {
    '病假':'病假','病':'病假','事假':'事假','事':'事假',
    '特休':'特休','特':'特休','曠職':'曠職','曠':'曠職',
    '出勤':'出勤','正常':'出勤','休假':'休假','休':'休假',
    '公假':'公假','公':'公假','產假':'產假','喪假':'喪假','婚假':'婚假',
    '例':'例假','例假':'例假','例休':'例休',
    '未':'未到','離':'離職','離職':'離職',
    '下休(事)':'事假','下休(特休)':'特休','下休(曠)':'曠職',
    '病(無薪)':'病假','無薪病假':'病假',
    '國':'國定假日','國定':'國定假日','國假':'國定假日',
    '補':'補休','補休':'補休',
  },
};

let prev; try { prev=$('解析分頁並組裝URL').first().json; } catch(e) { prev={}; }
const api = $input.first().json;
const wh=prev.warehouse||'', st=prev.sheetType||'work', sn=prev.sheetName||'';
const allSN=prev.allSheetNames||[], date=prev.date||'', intent=prev.intent||'';
const lt=prev.leaveType||'', nr=prev.needReport||false, oq=prev.originalQuery||'';
const dm=prev.dateMode||'day';
const emails=prev.emails||[];
const personName=prev.personName||'';
const dateFrom=prev.dateFrom||'', dateTo=prev.dateTo||'';
const pw=prev.warning||null;

if (api.error||!api.values) return [{ json:{warehouse:wh,sheetType:st,sheetName:sn,allSheetNames:allSN,date,dateFrom,dateTo,dateMode:dm,intent,leaveType:lt,needReport:nr,originalQuery:oq,personName,emails,warning:pw,rows:[],totalRows:0,success:false,error:wh+'「'+sn+'」無資料'} }];

const hdr=api.values[0]||[], raw=api.values.slice(1);

// Header 正規化比對：移除換行、空白、括號內容
function normalizeH(s) { return s.replace(/[\n\r\s]/g,'').replace(/\(.*?\)/g,'').trim(); }
function fc(h, aliases) {
  for (const a of aliases) {
    const na = normalizeH(a);
    const i = h.findIndex(z => z && normalizeH(z) === na);
    if (i !== -1) return i;
  }
  // 子字串比對
  for (const a of aliases) {
    const i = h.findIndex(z => z && normalizeH(z).includes(normalizeH(a)));
    if (i !== -1) return i;
  }
  return -1;
}

function ns(v) {
  if (!v || v.trim()==='') return { status:'', ok:true };
  const lv = v.trim();
  for (const [k, m] of Object.entries(CONFIG.leaveStatusMapping)) {
    if (lv === k) return { status:m, ok:true };
  }
  return { status:lv, ok:false };
}

let rows = [];

if (st === 'work') {
  // 出勤時數表：每列一筆打卡記錄
  const cm = {
    date: fc(hdr, ['日期','Date']),
    department: fc(hdr, ['組別','部門','Department','組','Group']),
    shift: fc(hdr, ['班別','Shift','班次']),
    name: fc(hdr, ['姓名','Name','員工姓名']),
    clockIn: fc(hdr, ['上班時間','上班','ClockIn']),
    clockOut: fc(hdr, ['下班時間','下班','ClockOut']),
    workHours: fc(hdr, ['工作總時數','工時','Hours','總工時']),
    overtimeHours: fc(hdr, ['加班總時數','OvertimeHours','加班時數','加班']),
    note: fc(hdr, ['備註','Note','Remark']),
  };
  for (const r of raw) {
    const g = f => { const i = cm[f]; return i>=0 && r[i]!==undefined ? String(r[i]).trim() : ''; };
    const name = g('name');
    if (!name) continue;
    rows.push({
      date: g('date'), department: g('department'), shift: g('shift'), name,
      clockIn: g('clockIn'), clockOut: g('clockOut'),
      workHours: g('workHours'), overtimeHours: g('overtimeHours'),
      attendanceStatus: '出勤', leaveType: '', note: g('note'), warehouse: wh,
    });
  }
} else {
  // 班表：日期欄從第一個「X/X」格式的欄位開始
  const ni = fc(hdr, ['姓名','Name','員工姓名']);
  const di = fc(hdr, ['組別','部門','Department','組']);
  const si = fc(hdr, ['班別','Shift','班次']);
  // 找到第一個日期欄（格式 X/X）
  let dsc = -1;
  for (let i = 0; i < hdr.length; i++) {
    if (hdr[i] && /^\d{1,2}\/\d{1,2}$/.test(hdr[i].trim())) { dsc = i; break; }
  }
  if (dsc === -1) dsc = 8; // fallback
  const dh = hdr.slice(dsc);

  for (const r of raw) {
    const pn = ni>=0 ? String(r[ni]||'').trim() : '';
    const dp = di>=0 ? String(r[di]||'').trim() : '';
    const sh = si>=0 ? String(r[si]||'').trim() : '';
    if (!pn) continue;
    for (let i = 0; i < dh.length; i++) {
      const cv = r[dsc+i];
      // 空白 = 出勤，跳過
      if (cv === undefined || cv === null || String(cv).trim() === '') continue;
      const s = ns(String(cv));
      rows.push({
        date: dh[i] ? String(dh[i]).trim() : '',
        department: dp, shift: sh, name: pn,
        workHours: '', overtimeHours: '', clockIn: '', clockOut: '',
        attendanceStatus: s.status, leaveType: s.status,
        note: '', warehouse: wh,
        ...(!s.ok ? { unresolvedStatus: true } : {}),
      });
    }
  }
}

return [{json:{warehouse:wh,sheetType:st,sheetName:sn,allSheetNames:allSN,date,dateFrom,dateTo,dateMode:dm,intent,leaveType:lt,needReport:nr,originalQuery:oq,personName,emails,warning:pw,rows,totalRows:rows.length,success:true}}];

// 合併所有倉別資料
const all=$input.all(), mr=[], wn=[], er=[];
let date='',dateFrom='',dateTo='',dateMode='day',intent='',lt='',nr=false,oq='',em=[],pn=''; const wl=[];
for(const it of all){const d=it.json;
  if(!date)date=d.date||'';if(!dateFrom)dateFrom=d.dateFrom||'';if(!dateTo)dateTo=d.dateTo||'';
  if(dateMode==='day')dateMode=d.dateMode||'day';
  if(!intent)intent=d.intent;if(!lt)lt=d.leaveType;if(!nr)nr=d.needReport;if(!oq)oq=d.originalQuery;if(!pn)pn=d.personName||'';if(!em.length&&d.emails?.length)em=d.emails;
  if(!wl.includes(d.warehouse))wl.push(d.warehouse);
  if(d.warning)wn.push(d.warning);if(!d.success){er.push(d.error||d.warehouse+' 失敗');continue;}
  if(d.rows?.length)mr.push(...d.rows);
}
return [{json:{date,dateFrom,dateTo,dateMode,intent,leaveType:lt,needReport:nr,originalQuery:oq,warehouses:wl,rows:mr,totalRows:mr.length,warnings:wn.length?wn:undefined,errors:er.length?er:undefined,personName:pn,emails:em,success:er.length===0}}];

// 查詢與統計（支援單日 + 整月 + 區間）
const AV = ['出勤','正常',''];
const d = $input.first().json;
const { date, dateFrom, dateTo, intent, leaveType:lt, originalQuery:oq, rows, warehouses:wh, warnings, errors, emails, personName:pn } = d;
const dateMode = d.dateMode || 'day';

// 日期轉數字（用於區間比對）
function toNum(ds) {
  // "2026-03-15" → 20260315, "3/15" → M*100+D
  let m = String(ds).match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/);
  if (m) return +m[1]*10000 + +m[2]*100 + +m[3];
  m = String(ds).match(/^(\d{1,2})\/(\d{1,2})$/);
  if (m) return new Date().getFullYear()*10000 + +m[1]*100 + +m[2];
  m = String(ds).match(/^(\d{4})\/(\d{1,2})\/(\d{1,2})$/);
  if (m) return +m[1]*10000 + +m[2]*100 + +m[3];
  return 0;
}

function matchDate(rd, mode) {
  if (!rd) return false;
  rd = String(rd).trim();
  if (mode === 'range') {
    const n = toNum(rd), nf = toNum(dateFrom), nt = toNum(dateTo);
    return n >= nf && n <= nt;
  }
  if (mode === 'month') {
    const parts = (date||'').split('-');
    if (parts.length !== 2) return false;
    const tM = parseInt(parts[1]);
    let m = rd.match(/^(\d{1,2})\/(\d{1,2})$/);
    if (m) return +m[1] === tM;
    m = rd.match(/^(\d{4})[\/-](\d{1,2})[\/-](\d{1,2})$/);
    if (m) return +m[2] === tM;
    return false;
  }
  // day mode
  const td = date || '';
  if (rd === td) return true;
  const p = td.split('-');
  if (p.length !== 3) return false;
  const [tY,tM,tD] = p.map(Number);
  let m = rd.match(/^(\d{1,2})\/(\d{1,2})$/);
  if (m) return +m[1]===tM && +m[2]===tD;
  m = rd.match(/^(\d{4})[\/-](\d{1,2})[\/-](\d{1,2})$/);
  if (m) return +m[1]===tY && +m[2]===tM && +m[3]===tD;
  return false;
}

function buildDetail(list, showDate) {
  const grouped = {};
  for (const r of list) {
    const t = r.leaveType || r.attendanceStatus || '未分類';
    if (!grouped[t]) grouped[t] = {};
    const key = [r.warehouse, r.department, r.shift, r.name].join('|');
    if (!grouped[t][key]) grouped[t][key] = { info: r, dates: [] };
    if (r.date) grouped[t][key].dates.push(r.date);
  }
  const lines = [];
  for (const [type, people] of Object.entries(grouped)) {
    const uniqueCount = Object.keys(people).length;
    lines.push('');
    lines.push('【' + type + '】' + uniqueCount + ' 人');
    for (const [key, data] of Object.entries(people)) {
      const p = data.info;
      const parts = [p.warehouse, p.department, p.shift, p.name].filter(Boolean);
      let line = '  ' + parts.join(' / ');
      if (showDate && data.dates.length > 0) {
        line += '：' + data.dates.join(', ') + ' 總計：' + data.dates.length + '天';
      }
      lines.push(line);
    }
  }
  return lines.join('\n');
}

function buildWorkDetail(list) {
  const lines = [];
  const byDept = {};
  for (const r of list) {
    const dept = r.department || '未分組';
    if (!byDept[dept]) byDept[dept] = [];
    byDept[dept].push(r);
  }
  for (const [dept, people] of Object.entries(byDept)) {
    lines.push('');
    lines.push('【' + dept + '】' + people.length + ' 筆');
    for (const p of people) {
      const wh = p.workHours ? p.workHours + 'h' : '-';
      const ot = p.overtimeHours ? '+' + p.overtimeHours + 'h加班' : '';
      const time = (p.clockIn || p.clockOut) ? '（' + (p.clockIn||'?') + '~' + (p.clockOut||'?') + '）' : '';
      const dt = p.date ? p.date + ' ' : '';
      lines.push('  ' + dt + [p.shift, p.name].filter(Boolean).join('/') + ' ' + wh + ot + ' ' + time);
      if (p.note) lines.push('    備註：' + p.note);
    }
  }
  return lines.join('\n');
}

// 日期標籤
let dateLabel;
if (dateMode === 'range') {
  dateLabel = dateFrom + ' ~ ' + dateTo;
} else if (dateMode === 'month') {
  dateLabel = (date||'').replace(/^(\d{4})-0?(\d{1,2})$/, '$1年$2月');
} else {
  dateLabel = date || '';
}

const showDate = dateMode !== 'day';

// 篩選資料
let df;
if (dateMode === 'month') {
  df = rows;
} else {
  df = rows.filter(r => matchDate(r.date, dateMode));
}
if (pn) df = df.filter(r => r.name && r.name.includes(pn));

let res = {};
switch (intent) {
case 'leave_status':
case 'leave_stats': {
  const lr = df.filter(r => { const s = r.attendanceStatus || r.leaveType || ''; return s && !AV.includes(s); });
  const fr = lt ? lr.filter(r => (r.leaveType || r.attendanceStatus) === lt) : lr;
  const detail = buildDetail(fr, showDate);
  const label = lt ? lt + '統計' : '請假統計';
  const uniqueNames = new Set(fr.map(r => r.warehouse + '|' + r.name));
  const nameTag = pn ? ' 【' + pn + '】' : '';
  res = { success:true, query:oq, intent, date, dateFrom, dateTo, dateMode,
    summaryText: dateLabel + ' ' + label + nameTag + '：共 ' + uniqueNames.size + ' 人（' + fr.length + ' 人次），倉別：' + wh.join(', ') + '\n' + detail,
    detailText: detail,
    totals: { totalPeople: uniqueNames.size, totalEntries: fr.length, byWarehouse:{}, byLeaveType:{} }, rows:fr };
  for (const r of fr) {
    res.totals.byWarehouse[r.warehouse] = (res.totals.byWarehouse[r.warehouse]||0) + 1;
    const t = r.leaveType || '未分類';
    res.totals.byLeaveType[t] = (res.totals.byLeaveType[t]||0) + 1;
  }
  break; }
case 'sick_leave_stats': {
  const sr = df.filter(r => (r.leaveType||r.attendanceStatus||'').trim() === '病假');
  const detail = buildDetail(sr, showDate);
  const uniqueNames = new Set(sr.map(r => r.warehouse + '|' + r.name));
  const nameTag = pn ? ' 【' + pn + '】' : '';
  res = { success:true, query:oq, intent, date, dateFrom, dateTo, dateMode,
    summaryText: dateLabel + ' 病假統計' + nameTag + '：共 ' + uniqueNames.size + ' 人（' + sr.length + ' 人次），倉別：' + wh.join(', ') + '\n' + detail,
    detailText: detail,
    totals: { totalPeople: uniqueNames.size, totalEntries: sr.length, byWarehouse:{} }, rows:sr };
  for (const r of sr) res.totals.byWarehouse[r.warehouse] = (res.totals.byWarehouse[r.warehouse]||0) + 1;
  break; }
case 'attendance_detail': {
  const detail = buildDetail(df, showDate);
  const nameTag = pn ? ' 【' + pn + '】' : '';
  res = { success:true, query:oq, intent, date, dateFrom, dateTo, dateMode,
    summaryText: dateLabel + ' 出勤明細' + nameTag + '：共 ' + df.length + ' 筆，倉別：' + wh.join(', ') + '\n' + detail,
    detailText: detail,
    totals: { totalRecords:df.length, byWarehouse:{}, byDepartment:{} }, rows:df };
  for (const r of df) {
    res.totals.byWarehouse[r.warehouse] = (res.totals.byWarehouse[r.warehouse]||0) + 1;
    if (r.department) res.totals.byDepartment[r.department] = (res.totals.byDepartment[r.department]||0) + 1;
  }
  break; }
case 'attendance_stats': {
  const detail = buildWorkDetail(df);
  const tw = df.reduce((s,r) => s + (parseFloat(r.workHours)||0), 0);
  const to = df.reduce((s,r) => s + (parseFloat(r.overtimeHours)||0), 0);
  const nameTag = pn ? ' 【' + pn + '】' : '';
  res = { success:true, query:oq, intent, date, dateFrom, dateTo, dateMode,
    summaryText: dateLabel + ' 出勤時數' + nameTag + '：' + df.length + ' 人，工時 ' + tw.toFixed(1) + 'h，加班 ' + to.toFixed(1) + 'h，倉別：' + wh.join(', ') + '\n' + detail,
    detailText: detail,
    totals: { totalRecords:df.length, totalWorkHours:tw.toFixed(1), totalOvertimeHours:to.toFixed(1), byWarehouse:{} }, rows:df };
  for (const r of df) {
    if (!res.totals.byWarehouse[r.warehouse]) res.totals.byWarehouse[r.warehouse] = { count:0, wh:0, ot:0 };
    res.totals.byWarehouse[r.warehouse].count++;
    res.totals.byWarehouse[r.warehouse].wh += parseFloat(r.workHours)||0;
    res.totals.byWarehouse[r.warehouse].ot += parseFloat(r.overtimeHours)||0;
  }
  break; }
default: res = { success:false, query:oq, error:'無法識別意圖：'+intent }; }

if (warnings?.length) res.warnings = warnings;
if (errors?.length) { res.errors = errors; if (res.rows?.length === 0) { res.success = false; res.summaryText = '部分倉別讀取失敗'; } }
if (res.rows?.length === 0 && res.success) { res.success = false; res.summaryText = dateLabel + ' 查無資料（' + wh.join(', ') + '）'; }

res.emailSubject = '[出勤報表] ' + dateLabel + ' ' + (lt||intent) + ' - ' + wh.join(', ');
res.emailBody = res.summaryText || '';
res.emails = emails || [];
return [{json:res}];

// 組合最終回傳結果
const queryResult = $('查詢與統計').first().json;
const emailResult = $input.first().json;
return [{ json: {
  ...queryResult,
  email: emailResult.success ? emailResult.message : (emailResult.error || '未寄送'),
}}];
